const f=(v,d=2)=>typeof v==="number"?v.toLocaleString(undefined,{minimumFractionDigits:d,maximumFractionDigits:d}):v;
const sg=v=>v>0?"+":"";
const dc=(v,inv)=>{const p=inv?v<0:v>0;const n=inv?v>0:v<0;return p?C.pos:n?C.neg:C.muted;};
const dg=(v,inv)=>{const p=inv?v<0:v>0;const n=inv?v>0:v<0;return p?"\u25B2":n?"\u25BC":"-";};
