// ═══════════════ SVG CHART ═══════════════
function SVGChart({data,color,dec,unit,height=220,levels}){
  const [hover,setHover]=useState(null);
  const hasLevels = levels && levels.length > 0;
  const TW=hasLevels?900:700, H=height;
  const PAD={t:12,r:hasLevels?140:16,b:28,l:56};
  // Historical data zone = left portion; projection zone = right portion
  const projW = hasLevels ? TW*0.28 : 0;
  const histW = TW - PAD.l - PAD.r - projW;
  const ch=H-PAD.t-PAD.b;
  const vals=data.map(d=>d.value);
  const allVals = hasLevels ? [...vals, ...levels.map(l=>l.value)] : vals;
  const mn=Math.min(...allVals),mx=Math.max(...allVals);
  const range=mx-mn||1;
  const yMin=mn-range*0.08,yMax=mx+range*0.08,yRange=yMax-yMin;
  const x=i=>PAD.l+(data.length>1?(i/(data.length-1)):0.5)*histW;
  const y=v=>PAD.t+(1-(v-yMin)/yRange)*ch;
  const pathD=data.map((d,i)=>`${i===0?"M":"L"}${x(i).toFixed(1)},${y(d.value).toFixed(1)}`).join(" ");
  const yTicks=5;
  const yLines=Array.from({length:yTicks},(_,i)=>yMin+(yRange*i/(yTicks-1)));
  const xEvery=Math.ceil(data.length/12);
  const evtIdxs=EVT.map(e=>{const idx=data.findIndex(d=>d.date===e.date);return idx>=0?{...e,idx}:null;}).filter(Boolean);
  // Projection endpoints
  const lastX = x(data.length-1);
  const lastY = y(data[data.length-1].value);
  const projEndX = PAD.l + histW + projW;
  return (
    <svg viewBox={`0 0 ${TW} ${H}`} style={{width:"100%",maxWidth:TW,display:"block",userSelect:"none"}}
      onMouseMove={e=>{const rect=e.currentTarget.getBoundingClientRect();const px=(e.clientX-rect.left)/rect.width*TW;const idx=Math.round(((px-PAD.l)/histW)*(data.length-1));if(idx>=0&&idx<data.length)setHover(idx);}}
      onMouseLeave={()=>setHover(null)}>
      <rect width={TW} height={H} fill={C.surface} rx={4}/>
      {/* Y grid + labels */}
      {yLines.map((v,i)=><g key={i}><line x1={PAD.l} y1={y(v)} x2={hasLevels?projEndX:TW-PAD.r} y2={y(v)} stroke={C.border} strokeWidth={0.5}/><text x={PAD.l-6} y={y(v)+3} textAnchor="end" fill={C.muted} fontSize={9} fontFamily={MONO}>{f(v,dec)}</text></g>)}
      {/* X labels */}
      {data.map((d,i)=>i%xEvery===0?<text key={i} x={x(i)} y={H-6} textAnchor="middle" fill={C.muted} fontSize={8} fontFamily={SANS}>{d.date}</text>:null)}
      {/* 1Y-ago reference line */}
      <line x1={PAD.l} y1={y(data[0].value)} x2={lastX} y2={y(data[0].value)} stroke={C.muted} strokeDasharray="4,3" strokeWidth={0.7} opacity={0.6}/>
      {/* Event markers */}
      {evtIdxs.map((e,i)=><line key={i} x1={x(e.idx)} y1={PAD.t} x2={x(e.idx)} y2={H-PAD.b} stroke={C.borderMed} strokeDasharray="3,3" strokeWidth={0.7}/>)}
      {/* Price line */}
      <path d={pathD} fill="none" stroke={color} strokeWidth={1.8} strokeLinecap="round" strokeLinejoin="round"/>
      {/* Projection cone */}
      {hasLevels&&(()=>{
        const bullY=y(levels[0].value), baseY=y(levels[1].value), bearY=y(levels[2].value);
        return <g>
          {/* Shaded cone between bull and bear */}
          <path d={`M${lastX},${lastY} L${projEndX},${bullY} L${projEndX},${bearY} Z`} fill={C.muted} opacity={0.04}/>
          {/* "Today" vertical line */}
          <line x1={lastX} y1={PAD.t} x2={lastX} y2={H-PAD.b} stroke={C.borderMed} strokeWidth={1} strokeDasharray="4,3"/>
          <text x={lastX} y={H-4} textAnchor="middle" fill={C.muted} fontSize={7} fontFamily={SANS}>Today</text>
          {/* Dec 31 label */}
          <text x={projEndX} y={H-4} textAnchor="middle" fill={C.muted} fontSize={7} fontFamily={SANS}>Dec 31</text>
          {/* Fan lines */}
          {levels.map((lv,i)=>{
            const endY=y(lv.value);
            return <g key={i}>
              <line x1={lastX} y1={lastY} x2={projEndX} y2={endY} stroke={lv.color} strokeWidth={1.3} strokeDasharray={i===1?"none":"6,4"} opacity={0.75}/>
              <circle cx={projEndX} cy={endY} r={3} fill={lv.color} opacity={0.8}/>
              {/* Price + pct label */}
              <text x={projEndX+8} y={endY-4} fill={lv.color} fontSize={9} fontWeight={600} fontFamily={MONO}>{f(lv.value,0)} ({lv.pct})</text>
              {/* Probability label */}
              <text x={projEndX+8} y={endY+8} fill={C.muted} fontSize={8} fontFamily={MONO}>{lv.prob}</text>
            </g>;
          })}
        </g>;
      })()}
      {/* Hover tooltip */}
      {hover!==null&&hover>=0&&hover<data.length&&(
        <g><line x1={x(hover)} y1={PAD.t} x2={x(hover)} y2={H-PAD.b} stroke={C.borderMed} strokeWidth={0.8}/>
        <circle cx={x(hover)} cy={y(data[hover].value)} r={4} fill={C.surface} stroke={color} strokeWidth={2}/>
        <rect x={Math.min(x(hover)+8,TW-160)} y={Math.max(y(data[hover].value)-38,4)} width={120} height={32} rx={4} fill={C.surface} stroke={C.border} strokeWidth={1}/>
        <text x={Math.min(x(hover)+14,TW-154)} y={Math.max(y(data[hover].value)-22,20)} fill={C.muted} fontSize={9} fontFamily={SANS}>{data[hover].date}</text>
        <text x={Math.min(x(hover)+14,TW-154)} y={Math.max(y(data[hover].value)-9,33)} fill={C.text} fontSize={12} fontWeight={700} fontFamily={MONO}>{f(data[hover].value,dec)} {unit}</text></g>
      )}
    </svg>
  );
}

