function ChartBox({id,onClose}){
  const m=CMETA[id],ind=IND.find(x=>x.id===id);
  const allData=useMemo(()=>id==="spread"?getSpreadHistory():getHistory(id),[id]);
  const [range,setRange]=useState("1Y");
  const [customFrom,setCustomFrom]=useState("2024-01-01");
  const [customTo,setCustomTo]=useState("2026-03-26");
  const data=useMemo(()=>filterByRange(allData,range,customFrom,customTo),[allData,range,customFrom,customTo]);
  if(!m||!data.length) return null;
  const vals=data.map(d=>d.value);
  const mn=Math.min(...vals),mx=Math.max(...vals);
  const first=vals[0],last=vals[vals.length-1];
  const chg=last-first,pct=first!==0?(chg/first)*100:0;
  const rangeLabel=range==="custom"?"Custom":range;
  const RANGES=["1D","1W","1M","3M","6M","YTD","1Y","MAX","custom"];
  const RLABELS={"1D":"1D","1W":"1W","1M":"1M","3M":"3M","6M":"6M","YTD":"YTD","1Y":"1Y","MAX":"MAX","custom":"Custom"};
  return (
    <div style={{background:C.surface,borderBottom:`1px solid ${C.border}`,padding:"14px 24px 10px"}}>
      {/* Row 1: Title + value + close */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8,flexWrap:"wrap",gap:8}}>
        <div style={{display:"flex",alignItems:"baseline",gap:10,flexWrap:"wrap"}}>
          <span style={{fontSize:13,fontWeight:700}}>{m.label}</span>
          <span style={{fontSize:18,fontWeight:700,fontFamily:MONO}}>{f(ind.v,m.dec)}</span>
          {m.unit&&<span style={{fontSize:11,color:C.muted}}>{m.unit}</span>}
          <span style={{fontSize:11,fontWeight:600,fontFamily:MONO,color:dc(chg,ind.inv)}}>{sg(chg)}{f(chg,m.dec)} ({sg(pct)}{f(pct,1)}%) {rangeLabel}</span>
          <span style={{fontSize:10,color:C.muted}}>Range: {f(mn,m.dec)} - {f(mx,m.dec)}</span>
        </div>
        <button onClick={onClose} style={{background:"none",border:`1px solid ${C.border}`,borderRadius:4,padding:"3px 10px",fontSize:11,color:C.muted,cursor:"pointer",fontFamily:SANS}}>{"\u2715"} Close</button>
      </div>
      {/* Row 2: Range toggles + custom date inputs */}
      <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:10,flexWrap:"wrap"}}>
        {RANGES.map(r=>(
          <button key={r} onClick={()=>setRange(r)} style={{
            padding:"3px 10px",fontSize:10,fontWeight:range===r?600:400,fontFamily:SANS,
            color:range===r?C.text:C.muted,background:range===r?C.bg:"transparent",
            border:`1px solid ${range===r?C.borderMed:C.border}`,borderRadius:3,cursor:"pointer",
          }}>{RLABELS[r]}</button>
        ))}
        {range==="custom"&&(
          <div style={{display:"flex",alignItems:"center",gap:4,marginLeft:6}}>
            <input type="date" value={customFrom} onChange={e=>setCustomFrom(e.target.value)}
              style={{fontSize:10,fontFamily:MONO,padding:"2px 6px",border:`1px solid ${C.border}`,borderRadius:3,color:C.text,background:C.surface,outline:"none"}}
              min="2024-01-01" max="2026-03-26"/>
            <span style={{fontSize:10,color:C.muted}}>to</span>
            <input type="date" value={customTo} onChange={e=>setCustomTo(e.target.value)}
              style={{fontSize:10,fontFamily:MONO,padding:"2px 6px",border:`1px solid ${C.border}`,borderRadius:3,color:C.text,background:C.surface,outline:"none"}}
              min="2024-01-01" max="2026-03-26"/>
          </div>
        )}
        <span style={{fontSize:9,color:C.muted,marginLeft:4}}>{data.length} pts</span>
      </div>
      {/* Chart */}
      {(()=>{
        const spxLevels = id==="spx" ? [
          {value:7125,pct:"+10%",prob:"Prob(>7,125) ~37%",color:C.pos},
          {value:6477,pct:"~0%",prob:"Prob(>6,477) ~59%",color:C.warn},
          {value:5829,pct:"-10%",prob:"Prob(<5,829) ~25%",color:C.neg},
        ] : null;
        return <SVGChart data={data} color={m.color} dec={m.dec} unit={m.unit||""} levels={spxLevels}/>;
      })()}
      {/* Event legend */}
      <div style={{display:"flex",gap:14,flexWrap:"wrap",marginTop:6,paddingTop:6,borderTop:`1px solid ${C.border}`}}>
        {EVT.map((e,i)=><span key={i} style={{fontSize:9,color:C.muted}}><span style={{color:C.borderMed,fontWeight:700}}>|</span> {e.date} -- {e.label}</span>)}
      </div>
    </div>
  );
}
