function TimelineView(){
  return <Card>
    <SH>Trump Public Statements on US-Iran-Israel War -- Reference Appendix</SH>
    <div style={{fontSize:9,color:C.muted,marginBottom:12,padding:"6px 10px",background:C.bg,borderRadius:4}}>
      Sourced from official remarks, White House statements, Reuters, AP, NPR, CNBC, Al Jazeera, Truth Social. Direct quotes or clearly attributed statements only. Not used in any model scoring or calculations. Click source to view original.
    </div>
    <div style={{display:"flex",flexDirection:"column"}}>
      {TIMELINE.map((t,i)=>{
        const isNew = i===0 || TIMELINE[i-1].date !== t.date;
        return <div key={i} style={{display:"flex",gap:12,padding:"7px 0",borderTop:isNew&&i>0?`1px solid ${C.border}`:"none"}}>
          <div style={{width:48,flexShrink:0,textAlign:"right"}}>
            {isNew && <span style={{fontSize:11,fontWeight:600,color:C.text,fontFamily:MONO}}>{t.date}</span>}
          </div>
          <div style={{width:1,background:C.border,flexShrink:0}}/>
          <div style={{flex:1}}>
            <div style={{fontSize:10,color:C.muted,marginBottom:2}}>{t.ctx}</div>
            <div style={{fontSize:12,color:C.textSec,lineHeight:1.5,fontStyle:"italic"}}>"{t.quote}"</div>
            <a href={t.url} target="_blank" rel="noopener noreferrer" style={{fontSize:9,color:C.info,textDecoration:"none",borderBottom:`1px dashed ${C.info}40`,marginTop:2,display:"inline-block"}}>{t.src}</a>
          </div>
        </div>;
      })}
    </div>
  </Card>;
}
function Geo(){
  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    <Card><SH>Geopolitical Overlay</SH>{GEO.map((g,i)=><div key={i} style={{padding:"9px 0",borderBottom:i<GEO.length-1?`1px solid ${C.border}`:"none",display:"flex",gap:14,alignItems:"flex-start"}}><a href={g.url} target="_blank" rel="noopener noreferrer" style={{fontSize:10,color:C.info,fontWeight:600,minWidth:105,flexShrink:0,paddingTop:1,textDecoration:"none",cursor:"pointer",borderBottom:`1px dashed ${C.info}40`}}>{g.src}</a><span style={{fontSize:12,color:C.textSec,lineHeight:1.5}}>{g.text}</span></div>)}</Card>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
      <Card><SH>Strait of Hormuz Status</SH><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:16,marginBottom:14}}><KPI l="Status" v={HMZ.status} c={C.neg}/><KPI l="Days Disrupted" v={String(HMZ.days)} c={C.warn}/><KPI l="Ceasefire Prob." v={`~${HMZ.cf}%`} c={C.muted}/></div><div style={{fontSize:11,color:C.textSec,lineHeight:1.55}}>Iran selectively allowing neutral-flag vessels (Pakistan, India, Turkey). US/Israel/Western allies fully blocked. US military campaign to open strait ongoing since Mar 19.</div></Card>
      <Card><SH>Scenario Probabilities</SH><ScenarioList/></Card>
    </div>
  </div>;
}
function ScenarioList(){
  const [open,setOpen]=useState(null);
  return <div>{HMZ.sc.map((s,i)=>{
    const isOpen=open===i;
    return <div key={i} style={{marginBottom:i<HMZ.sc.length-1?6:0}}>
      <div onClick={()=>setOpen(isOpen?null:i)} style={{cursor:"pointer",display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:3,padding:"2px 0"}}>
        <div style={{display:"flex",alignItems:"center",gap:6}}>
          <span style={{fontSize:9,color:C.muted,transition:"transform 0.15s",transform:isOpen?"rotate(90deg)":"rotate(0deg)"}}>{"\u25B6"}</span>
          <span style={{fontSize:11,color:C.textSec}}>{s.l}</span>
        </div>
        <span style={{fontSize:11,fontWeight:700,color:C.text,fontFamily:MONO}}>{s.p}%</span>
      </div>
      <div style={{height:4,background:C.border,borderRadius:2,overflow:"hidden",marginBottom:isOpen?6:0}}>
        <div style={{height:"100%",borderRadius:2,width:`${s.p}%`,background:s.p>=60?C.neg:s.p>=30?C.warn:C.pos,opacity:0.65}}/>
      </div>
      {isOpen&&<div style={{fontSize:10,color:C.textSec,lineHeight:1.5,padding:"4px 0 6px 15px",borderLeft:`2px solid ${C.border}`}}>{s.why}</div>}
    </div>;
  })}</div>;
}
function KPI({l,v,c}){return <div><div style={{fontSize:10,color:C.muted,fontWeight:500,marginBottom:4,letterSpacing:0.3}}>{l}</div><div style={{fontSize:16,fontWeight:700,color:c,fontFamily:MONO}}>{v}</div></div>;}
function Card({children}){return <div style={{background:C.surface,border:`1px solid ${C.border}`,borderRadius:6,padding:"16px 20px"}}>{children}</div>;}
function SH({children}){return <div style={{fontSize:10,fontWeight:600,color:C.muted,letterSpacing:0.6,textTransform:"uppercase",marginBottom:12,paddingBottom:8,borderBottom:`1px solid ${C.border}`}}>{children}</div>;}
